import { Droplets, Waves, Wind } from "lucide-react";
import StrategicBanner from "@/components/StrategicBanner";
import StatCard from "@/components/StatCard";
import MekongSentinelCard from "@/components/MekongSentinelCard";

export default function DashboardPage() {
  return (
    <div className="max-w-[1400px] mx-auto space-y-6">
      {/* ROW 1: STRATEGIC BANNER */}
      <StrategicBanner />

      {/* ROW 2: STATS & SENTINEL */}
      <div className="grid grid-cols-12 gap-6">
        
        {/* LEFT COLUMN: STATS & MAP */}
        <div className="col-span-12 lg:col-span-8 space-y-6">
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <StatCard 
              title="Live Salinity" 
              value="0.45" 
              unit="g/L" 
              subtext="Stable for 4h" 
              icon={Droplets} 
            />
            <StatCard 
              title="Tidal Level" 
              value="+1.2" 
              unit="meters" 
              subtext="High Tide Peak in 22m" 
              subtextColor="text-orange-500" 
              icon={Waves} 
              iconColor="text-blue-400"
            />
            <StatCard 
              title="Wind / Velocity" 
              value="12" 
              unit="km/h SE" 
              subtext="Dominant pushing inland" 
              subtextColor="text-slate-500" 
              icon={Wind} 
              iconColor="text-slate-400"
            />
          </div>

          {/* MAP PLACEHOLDER */}
          <div className="bg-slate-200 h-[450px] rounded-3xl border border-slate-200 relative overflow-hidden shadow-inner group">
            <div className="absolute inset-0 bg-[url('https://api.mapbox.com/styles/v1/mapbox/satellite-v9/static/106.5,10.2,9,0/1200x600?access_token=YOUR_MAPBOX_TOKEN')] bg-cover bg-center transition-transform duration-700 group-hover:scale-105" />
            <div className="absolute top-6 left-6 bg-white/90 backdrop-blur-md p-4 rounded-2xl shadow-xl border border-white/20">
              <p className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Salinity Hotspots</p>
              <p className="text-[10px] text-slate-500 font-bold uppercase mt-1">Tiền Giang - Bến Tre Region</p>
            </div>
            <button className="absolute bottom-6 right-6 bg-slate-950 text-white text-[10px] font-black uppercase tracking-widest px-6 py-3 rounded-xl shadow-2xl hover:bg-cyan-600 transition-colors">
              Open Full Map
            </button>
          </div>
        </div>

        {/* RIGHT COLUMN: AI AGENT LOGIC */}
        <div className="col-span-12 lg:col-span-4 space-y-6">
          <MekongSentinelCard />
          
          <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
            <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest mb-6">Infrastructure Status</h4>
            <div className="space-y-5">
              {[
                { label: "Sensor Connectivity", val: "98.2%", color: "text-green-500" },
                { label: "Remote Station Power", val: "84% Avg", color: "text-blue-500" },
                { label: "Model Accuracy", val: "99.4%", color: "text-green-500" }
              ].map(stat => (
                <div key={stat.label} className="flex justify-between items-center text-[11px] font-bold uppercase tracking-tight">
                  <span className="text-slate-500">{stat.label}</span>
                  <span className={stat.color}>{stat.val}</span>
                </div>
              ))}
            </div>
          </div>
        </div>

      </div>
    </div>
  );
}