import { LucideIcon } from "lucide-react";
import { cn } from "@/lib/utils";

interface StatCardProps {
  title: string;
  value: string;
  unit: string;
  subtext: string;
  subtextColor?: string;
  icon: LucideIcon;
  iconColor?: string;
}

export default function StatCard({ 
  title, value, unit, subtext, subtextColor = "text-green-500", icon: Icon, iconColor = "text-cyan-500" 
}: StatCardProps) {
  return (
    <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm hover:shadow-md transition-shadow">
      <div className="flex justify-between items-start mb-6">
        <p className="text-[11px] font-black text-slate-400 uppercase tracking-widest">{title}</p>
        <div className={cn("p-2 bg-slate-50 rounded-lg border border-slate-100", iconColor)}>
          <Icon className="w-5 h-5" />
        </div>
      </div>
      
      <div className="flex items-baseline gap-1 mb-2">
        <span className="text-4xl font-black text-slate-900 tracking-tighter">{value}</span>
        <span className="text-sm font-bold text-slate-400 italic">{unit}</span>
      </div>
      
      <div className="flex items-center gap-1.5">
        <div className={cn("w-1.5 h-1.5 rounded-full", subtextColor.replace("text", "bg"))} />
        <p className={cn("text-[10px] font-bold uppercase tracking-tight", subtextColor)}>
          {subtext}
        </p>
      </div>
    </div>
  );
}