import { Target } from "lucide-react";

export default function StrategicBanner() {
  return (
    <div className="bg-[#0F172A] rounded-2xl p-7 text-white flex items-center justify-between shadow-xl relative overflow-hidden border border-slate-800">
      {/* Background Decor */}
      <div className="absolute top-0 right-0 w-1/3 h-full bg-gradient-to-l from-cyan-500/10 to-transparent z-0" />
      
      <div className="flex items-center gap-5 relative z-10">
        <div className="w-12 h-12 bg-green-500/10 rounded-xl flex items-center justify-center border border-green-500/20">
          <Target className="w-6 h-6 text-green-400" />
        </div>
        <div>
          <p className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em] mb-1">Strategic Objective</p>
          <h2 className="text-xl font-bold tracking-tight">Current Goal: Maintain Salinity <span className="text-cyan-400">&lt; 0.5 g/L</span> (Safe Level)</h2>
        </div>
      </div>

      <div className="flex items-center gap-8 relative z-10">
        <div className="text-right">
          <p className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">Current Variance</p>
          <p className="text-2xl font-black text-cyan-400 leading-none">-0.05 g/L</p>
        </div>
        <button className="bg-cyan-400 hover:bg-cyan-300 text-slate-950 font-black py-3 px-6 rounded-xl text-[11px] uppercase tracking-wider transition-all shadow-[0_0_20px_rgba(34,211,238,0.2)]">
          Adjust Thresholds
        </button>
      </div>
    </div>
  );
}